import type { CSSProperties, FunctionComponent, MouseEvent } from 'react';
import type { TippyProps } from '@andes-tippy-js/react';
import type { Instance } from 'tippy.js';

type PopperSpecificProps = {
  /**
   * Custom trigger. It's the node which opens the popper.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/popper#props | Documentation}
   */
  children?: TippyProps['children'];

  /**
   * Custom class.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/popper#props | Documentation}
   */
  className?: string;

  /**
   * Content within the popper.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/popper#props | Documentation}
   */
  content: TippyProps['content'];

  /** @internal */
  focusScope?: boolean;

  /**
   * Unique identifier.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/popper#props | Documentation}
   */
  id?: string;

  /**
   * Allows the component to be interactive, to hover over and click inside it.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/popper#props | Documentation}
   * @default false
   */
  interactive?: TippyProps['interactive'];

  /**
   * Callback fired when the user clicks anywhere outside of the popper.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/popper#props | Documentation}
   */
  onClickOutside?: (instance: Instance | null, event: MouseEvent) => void;

  /**
   * Callback fired when the popper closes.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/popper#props | Documentation}
   */
  onHidden?: (instance: Instance, _: { preventFocus?: boolean }) => void;

  /**
   * The padding size of the popper.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/popper#props | Documentation}
   * @default 0
   */
  paddingSize?: 0 | 16 | 24 | 32 | 40;

  /**
   * Position of the popper relative to the trigger.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/popper#props | Documentation}
   * @default 'bottom'
   */
  placement?: Exclude<
    TippyProps['placement'],
    'auto-end' | 'auto-start' | 'auto'
  >;

  /**
   * Specifies custom popper options. This gives you full control over the component positioning. See {@link https://popper.js.org/docs/v2 | Popper's docs} for details.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/popper#props | Documentation}
   */
  popperOptions?: TippyProps['popperOptions'];

  /**
   * Style object for popper card.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/popper#props | Documentation}
   */
  style?: CSSProperties;

  /**
   * Event or events that could open the popper. For example we could use `'mouseenter'`, `'click'`, `'focusin'`, `'focus'` or any combination of those options (only for uncontrolled mode).
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/popper#props | Documentation}
   * @default 'click focus''
   */
  trigger?: TippyProps['trigger'];

  /**
   * Controlled mode.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/popper#props | Documentation}
   */
  visible?: TippyProps['visible'];
};

type PopperProps = Omit<TippyProps, 'onClickOutside' | 'onHidden' | 'style'> &
  PopperSpecificProps;

/**
 * Popper is essentially a card which overlaps or "floats above" the content of an UI. It's the first step towards
 * having a more unified implementation of components with similar behavior, i.e.: a Tooltip's message or a
 * Dropdown's List.
 * This is an internal component, if you need to use it please contact us to follow the use case.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/popper#props | Documentation}
 * @example
 * import { Popper } from '@andes/popper';;
 *
 * const MyComponent = () => (
 *   <Popper content={<div>This is the content, could be another component or an HTML node</div>}>
 *     <button>This is a custom trigger</button>
 *   </Popper>
 * );
 */
export const Popper: FunctionComponent<PopperProps>;
